
$c-bg: #0d0d0d;
$c-panel: #1a1a1a;
$c-panel-light: #222;
$c-gold: #d4af37;
$c-gold-dim: #8a7326;
$c-gold-bright: #f0d060;
$c-text: #e0e0e0;
$c-text-dim: #888;
$c-red: #c54b4b;
$c-green: #4caf50;
$c-cyan: #4fc3f7;
$c-orange: #ff9800;
$c-pink: #ff5d8f;
$c-border: #333;

.mystic-container {
  width: 100%;
  background: $c-bg;
  color: $c-text;
  font-family: 'Noto Serif SC', 'STSong', serif;
  position: relative;
  border-radius: 8px;
  overflow: hidden;
}
.bg-pattern {
  position: absolute;
  inset: 0;
  opacity: 0.04;
  background-image:
    radial-gradient(circle at 20% 30%, rgba(212, 175, 55, 0.3) 1px, transparent 1px),
    radial-gradient(circle at 80% 70%, rgba(212, 175, 55, 0.2) 1px, transparent 1px);
  background-size:
    30px 30px,
    25px 25px;
  pointer-events: none;
}
.main-panel {
  position: relative;
  padding: 14px;
  background: linear-gradient(135deg, rgba(26, 26, 26, 0.6) 0%, rgba(13, 13, 13, 0.9) 100%);
  backdrop-filter: blur(4px);
}
.panel-decor {
  height: 2px;
  background: linear-gradient(90deg, transparent, $c-gold, transparent);
  margin: 10px 0;
}

// 头部
.header {
  text-align: center;
  margin-bottom: 12px;
}
.world-info {
  display: flex;
  justify-content: center;
  gap: 10px;
  align-items: center;
  font-size: 12px;
  color: $c-gold-dim;
}
.info-item i {
  margin-right: 3px;
  font-style: normal;
}
.divider {
  color: $c-gold-dim;
  opacity: 0.5;
}
.environment {
  color: $c-gold;
  font-size: 13px;
  margin-top: 5px;
  letter-spacing: 1px;
}

// 角色标签（v2：单角色）
.char-tabs {
  display: flex;
  margin-bottom: 14px;
}
.tab-item {
  flex: 1;
  text-align: center;
  padding: 10px;
  border: 1px solid $c-gold;
  border-radius: 8px;
  background: linear-gradient(135deg, rgba(212, 175, 55, 0.15) 0%, rgba(212, 175, 55, 0.03) 100%);
  box-shadow: 0 0 12px rgba(212, 175, 55, 0.15);
}
.char-name {
  display: block;
  color: $c-gold;
  font-size: 16px;
  font-weight: 600;
}
.char-role {
  display: block;
  font-size: 11px;
  color: $c-text-dim;
  margin-top: 2px;
}

// 植入（保留原样）
.implant-control {
  margin-bottom: 14px;
}
.control-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 10px;
}
.decor-line {
  flex: 1;
  height: 1px;
  background: linear-gradient(90deg, transparent, $c-gold-dim, transparent);
}
.control-header .title {
  color: $c-gold-bright;
  font-size: 14px;
  letter-spacing: 2px;
  font-weight: 600;
}
.target-hint {
  font-size: 12px;
  color: $c-text-dim;
  margin-bottom: 8px;
}
.target-hint strong {
  color: $c-gold;
}
.input-wrapper {
  display: flex;
  gap: 8px;
  align-items: center;
}
.input-wrapper input {
  flex: 1;
  background: $c-panel;
  border: 1px solid $c-border;
  border-radius: 5px;
  padding: 7px 10px;
  color: $c-text;
  font-size: 13px;
  font-family: inherit;
  transition: border-color 0.2s;
}
.input-wrapper input:focus {
  border-color: $c-gold-dim;
  outline: none;
}
.char-count {
  font-size: 10px;
  color: #555;
}
.char-count.at-limit {
  color: $c-red;
}
.submit-btn {
  padding: 7px 18px;
  background: linear-gradient(135deg, $c-gold-dim, $c-gold);
  border: none;
  border-radius: 5px;
  color: #000;
  cursor: pointer;
  font-weight: 700;
  font-size: 13px;
  transition: all 0.2s;
}
.submit-btn:hover:not(:disabled) {
  background: linear-gradient(135deg, $c-gold, $c-gold-bright);
}
.submit-btn:disabled {
  opacity: 0.35;
}
.implant-msg {
  font-size: 12px;
  margin-top: 6px;
  padding: 4px 8px;
  border-radius: 4px;
}
.implant-msg.success {
  color: $c-green;
  background: rgba(76, 175, 80, 0.1);
}
.implant-msg.error {
  color: $c-red;
  background: rgba(196, 75, 75, 0.1);
}
.implant-msg.warn {
  color: $c-orange;
  background: rgba(255, 152, 0, 0.1);
}

// 状态展示
.status-display {
  display: grid;
  grid-template-columns: 1fr 1.15fr;
  gap: 14px;
}
.col-left {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

// 阶段圆环
.stage-card {
  text-align: center;
  padding: 4px 0;
}
.stage-ring {
  position: relative;
  width: 90px;
  height: 90px;
  margin: 0 auto;
}
.circular-chart {
  width: 100%;
  height: 100%;
  transform: rotate(0deg);
}
.circle-bg {
  fill: none;
  stroke: #2a2a2a;
  stroke-width: 2;
}
.circle {
  fill: none;
  stroke: $c-gold;
  stroke-width: 2.8;
  stroke-linecap: round;
  filter: drop-shadow(0 0 4px rgba(212, 175, 55, 0.4));
  transition: stroke-dasharray 0.5s;
}
.stage-text {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
}
.stage-text .label {
  font-size: 10px;
  color: $c-text-dim;
  letter-spacing: 1px;
}
.stage-text .value {
  font-size: 15px;
  color: $c-gold-bright;
  font-weight: 600;
  margin-top: 2px;
}

// 数值条
.stats-group {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.stat-item {
  background: $c-panel;
  border-radius: 6px;
  padding: 8px 10px;
}
.stat-header {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
  margin-bottom: 4px;
}
.stat-header .name {
  color: $c-text-dim;
}
.stat-header .num {
  color: $c-gold;
  font-weight: 600;
}
.progress-track {
  height: 6px;
  background: #1a1a1a;
  border-radius: 3px;
  overflow: hidden;
}
.progress-bar {
  height: 100%;
  border-radius: 3px;
  transition: width 0.4s ease;
}
.stat-corruption {
  background: linear-gradient(90deg, #8a2be2, #c54b8f);
  box-shadow: 0 0 6px rgba(197, 75, 143, 0.3);
}
.stat-alert {
  background: linear-gradient(90deg, #4fc3f7, #0288d1);
  box-shadow: 0 0 6px rgba(2, 136, 209, 0.3);
}
.stat-desire {
  background: linear-gradient(90deg, #c54b8f, $c-pink);
}
.stat-husband {
  background: linear-gradient(90deg, #555, #999);
}

// 苏文卡
.suwen-card {
  background: $c-panel;
  border: 1px solid $c-border;
  border-radius: 8px;
  padding: 10px;
}
.suwen-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 5px;
}
.suwen-header .name {
  color: $c-gold;
  font-size: 14px;
  font-weight: 600;
}
.status-tag {
  font-size: 11px;
  padding: 2px 8px;
  border-radius: 10px;
  background: $c-panel-light;
}
.status-tag.home {
  background: rgba(196, 75, 75, 0.25);
  color: $c-red;
}
.status-tag.away {
  background: rgba(76, 175, 80, 0.25);
  color: $c-green;
}
.status-tag.sleeping {
  background: rgba(79, 195, 247, 0.25);
  color: $c-cyan;
}
.suwen-location {
  font-size: 12px;
  color: $c-text-dim;
  margin-bottom: 8px;
}
.suspicion-row {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 11px;
}
.suspicion-row .label {
  color: $c-text-dim;
}
.suspicion-track {
  flex: 1;
  height: 6px;
  background: #1a1a1a;
  border-radius: 3px;
  overflow: hidden;
}
.suspicion-fill {
  height: 100%;
  background: $c-orange;
  border-radius: 3px;
  transition: width 0.4s;
}
.suspicion-fill.danger {
  background: $c-red;
  box-shadow: 0 0 6px rgba(196, 75, 75, 0.5);
}
.suspicion-row .val {
  color: $c-gold;
  font-weight: 600;
}
.accel-hint {
  font-size: 12px;
  color: $c-orange;
  margin-top: 8px;
  padding: 4px 8px;
  background: rgba(255, 152, 0, 0.1);
  border-left: 2px solid $c-orange;
  border-radius: 3px;
}
.safe-indicator {
  font-size: 12px;
  color: $c-green;
  margin-top: 8px;
  display: flex;
  gap: 5px;
  align-items: center;
}

// 货币
.currency-card {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: $c-panel;
  border: 1px solid $c-border;
  border-radius: 8px;
  padding: 10px 14px;
}
.currency-card .label {
  color: $c-text-dim;
  font-size: 13px;
}
.currency-card .val {
  color: $c-gold-bright;
  font-size: 18px;
  font-weight: 700;
}

// 右栏
.col-right {
  display: flex;
  flex-direction: column;
  gap: 12px;
}
.detail-card {
  background: $c-panel;
  border: 1px solid $c-border;
  border-radius: 8px;
  padding: 10px 12px;
}
.section-title {
  color: $c-gold;
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 8px;
  border-bottom: 1px solid $c-border;
  padding-bottom: 4px;
  letter-spacing: 0.5px;
}
.section-title .count {
  color: $c-text-dim;
  font-weight: 400;
  font-size: 11px;
}

// 心境
.emotion-row {
  display: flex;
  gap: 8px;
  align-items: center;
  font-size: 13px;
  margin-bottom: 6px;
}
.emotion-row .label {
  color: $c-text-dim;
}
.emotion-val {
  color: $c-gold;
}
.emotion-val.vulnerable-glow {
  color: $c-pink;
  font-weight: 700;
  text-shadow: 0 0 8px rgba(255, 93, 143, 0.6);
  animation: vuln-pulse 1.5s ease-in-out infinite;
}
@keyframes vuln-pulse {
  0%,
  100% {
    opacity: 1;
    text-shadow: 0 0 8px rgba(255, 93, 143, 0.6);
  }
  50% {
    opacity: 0.75;
    text-shadow: 0 0 14px rgba(255, 93, 143, 0.9);
  }
}
.vulnerable-hint {
  display: flex;
  gap: 6px;
  align-items: center;
  padding: 5px 8px;
  background: rgba(255, 93, 143, 0.1);
  border: 1px solid rgba(255, 93, 143, 0.35);
  border-radius: 5px;
  font-size: 11px;
  color: $c-pink;
  margin-bottom: 6px;
}
.thought-bubble {
  font-size: 12px;
  color: #bbb;
  font-style: italic;
  margin-bottom: 4px;
}
.temperament {
  font-size: 11px;
  color: $c-text-dim;
}

// 念头
.empty {
  font-size: 12px;
  color: #444;
  text-align: center;
  padding: 8px 0;
}
.thought-item {
  background: $c-panel-light;
  border-radius: 6px;
  padding: 8px 10px;
  margin-bottom: 7px;
  border-left: 2px solid transparent;
  transition: border-color 0.2s;
}
.thought-item:hover {
  border-left-color: $c-gold-dim;
}
.thought-head {
  display: flex;
  gap: 6px;
  align-items: center;
  margin-bottom: 4px;
  flex-wrap: wrap;
}
.status-tag.growing {
  background: rgba(76, 175, 80, 0.25);
  color: $c-green;
}
.status-tag.pending {
  background: rgba(79, 195, 247, 0.25);
  color: $c-cyan;
}
.status-tag.rejected {
  background: rgba(196, 75, 75, 0.25);
  color: $c-red;
}
.status-tag.mature {
  background: rgba(212, 175, 55, 0.25);
  color: $c-gold;
}
.thought-type {
  font-size: 11px;
  color: $c-text-dim;
}
.thought-diff {
  font-size: 10px;
  color: $c-orange;
  padding: 1px 5px;
  border-radius: 3px;
  background: rgba(255, 152, 0, 0.1);
}
.thought-content {
  font-size: 13px;
  color: #ddd;
  margin-bottom: 5px;
}
.thought-progress {
  display: flex;
  align-items: center;
  gap: 8px;
}
.thought-progress .progress-bar {
  background: linear-gradient(90deg, $c-gold-dim, $c-gold);
}
.progress-text {
  font-size: 10px;
  color: $c-text-dim;
  white-space: nowrap;
}
.thought-reject {
  font-size: 11px;
  color: $c-red;
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.mini-btn {
  font-size: 10px;
  padding: 2px 10px;
  background: transparent;
  border: 1px solid $c-red;
  border-radius: 3px;
  color: $c-red;
  cursor: pointer;
  transition: all 0.2s;
}
.mini-btn:hover {
  background: rgba(196, 75, 75, 0.2);
}

// 习惯
.habit-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: $c-panel-light;
  border-radius: 5px;
  padding: 6px 10px;
  margin-bottom: 5px;
  font-size: 13px;
}
.habit-text {
  color: $c-green;
}
.sell-btn {
  font-size: 10px;
  padding: 3px 10px;
  background: rgba(212, 175, 55, 0.15);
  border: 1px solid $c-gold-dim;
  border-radius: 4px;
  color: $c-gold;
  cursor: pointer;
  transition: all 0.2s;
}
.sell-btn:hover {
  background: rgba(212, 175, 55, 0.25);
}
.habit-full-tip {
  font-size: 11px;
  color: $c-orange;
  margin-top: 6px;
  padding: 4px 8px;
  background: rgba(255, 152, 0, 0.08);
  border-radius: 4px;
}

// 仪容
.attire-tags {
  display: flex;
  gap: 6px;
  margin-bottom: 8px;
  flex-wrap: wrap;
}
.mini-tag {
  font-size: 11px;
  padding: 2px 8px;
  border-radius: 10px;
  background: rgba(212, 175, 55, 0.1);
  color: $c-gold;
}
.mini-tag.outline {
  background: transparent;
  border: 1px solid $c-gold-dim;
}
.clothing-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-bottom: 6px;
}
.clothing-item {
  font-size: 12px;
  color: #ccc;
}
.clothing-item .cl {
  display: inline-block;
  width: 30px;
  color: $c-text-dim;
  font-size: 11px;
}
.makeup-line {
  font-size: 12px;
  color: $c-text-dim;
  padding-top: 4px;
  border-top: 1px solid #2a2a2a;
}

@media (max-width: 480px) {
  .status-display {
    grid-template-columns: 1fr;
  }
}
